      }

      class BookCat {
        - Integer id;
        - Integer parentid;
        - Boolean isparent;
        - String name;
      }

      class Book {
        ..列举了部分私有属性..
        - Integer id;
        - Integer bookcat;
        - String bookname;
        - String isbn;
        - String publish;
        - Date pubdate;
      }

      Borrow "1" *-right- "1" BorrowId
      ReaderCat "1" o-right- "*" Reader
      Reader "1" -- "*" Punish
      Reader "1" -- "*" Book
      BookCat "1" o-right- "*" Book
    }
  }
}
